// App.js
import React, { useState, useEffect, useCallback, useRef } from 'react';
import {
  View,
  Text,
  TouchableOpacity,
  StyleSheet,
  ActivityIndicator,
  Alert,
  ScrollView,
  Linking,
} from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import * as AuthSession from 'expo-auth-session';
import * as WebBrowser from 'expo-web-browser';

WebBrowser.maybeCompleteAuthSession();

// ============================================================
// OAuth 2.0 Configuration
// WARNING: Storing client_secret in a mobile app is a security
// risk. Mobile apps are considered "public clients" and should
// use PKCE (Proof Key for Code Exchange) without a client_secret.
// This implementation includes client_secret as requested, but
// for production, consider using PKCE-only flow.
// ============================================================
const OAUTH_CONFIG = {
  clientId: 'your-client-id-here',
  clientSecret: 'your-client-secret-here', // SECURITY RISK: See warning above
  authorizationEndpoint: 'https://your-oauth-server.com/authorize',
  tokenEndpoint: 'https://your-oauth-server.com/token',
  revocationEndpoint: 'https://your-oauth-server.com/revoke',
  userInfoEndpoint: 'https://your-oauth-server.com/userinfo',
  scopes: ['openid', 'profile', 'email', 'offline_access'],
  redirectUri: AuthSession.makeRedirectUri({
    scheme: 'myapp',
    path: 'oauth/callback',
  }),
};

// Storage keys
const STORAGE_KEYS = {
  ACCESS_TOKEN: '@oauth_access_token',
  REFRESH_TOKEN: '@oauth_refresh_token',
  TOKEN_EXPIRY: '@oauth_token_expiry',
  USER_INFO: '@oauth_user_info',
};

// Token refresh buffer (refresh 5 minutes before expiry)
const TOKEN_REFRESH_BUFFER_SECONDS = 300;

// ============================================================
// Token Manager - Handles storage, retrieval, and refresh
// ============================================================
class TokenManager {
  static async storeTokens(accessToken, refreshToken, expiresIn) {
    const expiryTime = Date.now() + expiresIn * 1000;
    await AsyncStorage.multiSet([
      [STORAGE_KEYS.ACCESS_TOKEN, accessToken],
      [STORAGE_KEYS.REFRESH_TOKEN, refreshToken || ''],
      [STORAGE_KEYS.TOKEN_EXPIRY, expiryTime.toString()],
    ]);
    return { accessToken, refreshToken, expiryTime };
  }

  static async getTokens() {
    const values = await AsyncStorage.multiGet([
      STORAGE_KEYS.ACCESS_TOKEN,
      STORAGE_KEYS.REFRESH_TOKEN,
      STORAGE_KEYS.TOKEN_EXPIRY,
    ]);
    const accessToken = values[0][1];
    const refreshToken = values[1][1];
    const expiryTime = values[2][1] ? parseInt(values[2][1], 10) : null;

    if (!accessToken) return null;

    return { accessToken, refreshToken, expiryTime };
  }

  static async clearTokens() {
    await AsyncStorage.multiRemove([
      STORAGE_KEYS.ACCESS_TOKEN,
      STORAGE_KEYS.REFRESH_TOKEN,
      STORAGE_KEYS.TOKEN_EXPIRY,
      STORAGE_KEYS.USER_INFO,
    ]);
  }

  static isTokenExpired(expiryTime) {
    if (!expiryTime) return true;
    return Date.now() >= expiryTime - TOKEN_REFRESH_BUFFER_SECONDS * 1000;
  }

  static async exchangeCodeForTokens(code, codeVerifier) {
    const params = new URLSearchParams({
      grant_type: 'authorization_code',
      code,
      redirect_uri: OAUTH_CONFIG.redirectUri,
      client_id: OAUTH_CONFIG.clientId,
      client_secret: OAUTH_CONFIG.clientSecret,
    });

    if (codeVerifier) {
      params.append('code_verifier', codeVerifier);
    }

    const response = await fetch(OAUTH_CONFIG.tokenEndpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: params.toString(),
    });

    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}));
      throw new Error(
        errorData.error_description || errorData.error || 'Token exchange failed'
      );
    }

    const tokenData = await response.json();
    return TokenManager.storeTokens(
      tokenData.access_token,
      tokenData.refresh_token,
      tokenData.expires_in || 3600
    );
  }

  static async refreshAccessToken(refreshToken) {
    const params = new URLSearchParams({
      grant_type: 'refresh_token',
      refresh_token: refreshToken,
      client_id: OAUTH_CONFIG.clientId,
      client_secret: OAUTH_CONFIG.clientSecret,
    });

    const response = await fetch(OAUTH_CONFIG.tokenEndpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: params.toString(),
    });

    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}));
      throw new Error(
        errorData.error_description || errorData.error || 'Token refresh failed'
      );
    }

    const tokenData = await response.json();
    return TokenManager.storeTokens(
      tokenData.access_token,
      tokenData.refresh_token || refreshToken,
      tokenData.expires_in || 3600
    );
  }

  static async revokeToken(token) {
    if (!OAUTH_CONFIG.revocationEndpoint) return;

    try {
      await fetch(OAUTH_CONFIG.revocationEndpoint, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: new URLSearchParams({
          token,
          client_id: OAUTH_CONFIG.clientId,
          client_secret: OAUTH_CONFIG.clientSecret,
        }).toString(),
      });
    } catch (error) {
      console.warn('Token revocation failed:', error);
    }
  }

  static async getValidAccessToken() {
    const tokens = await TokenManager.getTokens();
    if (!tokens) return null;

    if (!TokenManager.isTokenExpired(tokens.expiryTime)) {
      return tokens.accessToken;
    }

    if (tokens.refreshToken) {
      try {
        const newTokens = await TokenManager.refreshAccessToken(tokens.refreshToken);
        return newTokens.accessToken;
      } catch (error) {
        console.error('Token refresh failed:', error);
        await TokenManager.clearTokens();
        return null;
      }
    }

    await TokenManager.clearTokens();
    return null;
  }
}

// ============================================================
// Authenticated API Client
// ============================================================
class ApiClient {
  static async fetch(url, options = {}) {
    const accessToken = await TokenManager.getValidAccessToken();
    if (!accessToken) {
      throw new Error('Not authenticated');
    }

    const headers = {
      ...options.headers,
      Authorization: `Bearer ${accessToken}`,
    };

    const response = await fetch(url, { ...options, headers });

    if (response.status === 401) {
      const tokens = await TokenManager.getTokens();
      if (tokens?.refreshToken) {
        try {
          const newTokens = await TokenManager.refreshAccessToken(tokens.refreshToken);
          headers.Authorization = `Bearer ${newTokens.accessToken}`;
          return fetch(url, { ...options, headers });
        } catch (refreshError) {
          await TokenManager.clearTokens();
          throw new Error('Session expired. Please log in again.');
        }
      }
      await TokenManager.clearTokens();
      throw new Error('Session expired. Please log in again.');
    }

    return response;
  }

  static async getUserInfo() {
    const response = await ApiClient.fetch(OAUTH_CONFIG.userInfoEndpoint);
    if (!response.ok) {
      throw new Error('Failed to fetch user info');
    }
    const userInfo = await response.json();
    await AsyncStorage.setItem(STORAGE_KEYS.USER_INFO, JSON.stringify(userInfo));
    return userInfo;
  }
}

// ============================================================
// Custom Hook: useOAuth
// ============================================================
function useOAuth() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [userInfo, setUserInfo] = useState(null);
  const [error, setError] = useState(null);
  const refreshTimerRef = useRef(null);

  const discovery = {
    authorizationEndpoint: OAUTH_CONFIG.authorizationEndpoint,
    tokenEndpoint: OAUTH_CONFIG.tokenEndpoint,
    revocationEndpoint: OAUTH_CONFIG.revocationEndpoint,
  };

  const [request, response, promptAsync] = AuthSession.useAuthRequest(
    {
      clientId: OAUTH_CONFIG.clientId,
      scopes: OAUTH_CONFIG.scopes,
      redirectUri: OAUTH_CONFIG.redirectUri,
      responseType: AuthSession.ResponseType.Code,
      usePKCE: true,
      extraParams: {
        access_type: 'offline',
        prompt: 'consent',
      },
    },
    discovery
  );

  const scheduleTokenRefresh = useCallback((expiryTime) => {
    if (refreshTimerRef.current) {
      clearTimeout(refreshTimerRef.current);
    }

    const now = Date.now();
    const refreshTime = expiryTime - TOKEN_REFRESH_BUFFER_SECONDS * 1000;
    const delay = Math.max(refreshTime - now, 0);

    refreshTimerRef.current = setTimeout(async () => {
      try {
        const tokens = await TokenManager.getTokens();
        if (tokens?.refreshToken) {
          const newTokens = await TokenManager.refreshAccessToken(tokens.refreshToken);
          console.log('Token automatically refreshed');
          scheduleTokenRefresh(newTokens.expiryTime);
        }
      } catch (refreshError) {
        console.error('Automatic token refresh failed:', refreshError);
        setIsAuthenticated(false);
        setUserInfo(null);
        await TokenManager.clearTokens();
      }
    }, delay);
  }, []);

  // Check for existing session on mount
  useEffect(() => {
    async function checkExistingSession() {
      try {
        const accessToken = await TokenManager.getValidAccessToken();
        if (accessToken) {
          setIsAuthenticated(true);
          const cachedUserInfo = await AsyncStorage.getItem(STORAGE_KEYS.USER_INFO);
          if (cachedUserInfo) {
            setUserInfo(JSON.parse(cachedUserInfo));
          }
          const tokens = await TokenManager.getTokens();
          if (tokens?.expiryTime) {
            scheduleTokenRefresh(tokens.expiryTime);
          }
        }
      } catch (err) {
        console.error('Session check failed:', err);
      } finally {
        setIsLoading(false);
      }
    }
    checkExistingSession();

    return () => {
      if (refreshTimerRef.current) {
        clearTimeout(refreshTimerRef.current);
      }
    };
  }, [scheduleTokenRefresh]);

  // Handle auth response
  useEffect(() => {
    async function handleResponse() {
      if (response?.type === 'success') {
        setIsLoading(true);
        setError(null);
        try {
          const { code } = response.params;
          const codeVerifier = request?.codeVerifier;
          const tokens = await TokenManager.exchangeCodeForTokens(code, codeVerifier);
          setIsAuthenticated(true);

          try {
            const info = await ApiClient.getUserInfo();
            setUserInfo(info);
          } catch (userInfoError) {
            console.warn('Failed to fetch user info:', userInfoError);
          }

          scheduleTokenRefresh(tokens.expiryTime);
        } catch (err) {
          console.error('Authentication failed:', err);
          setError(err.message);
          Alert.alert('Authentication Failed', err.message);
        } finally {
          setIsLoading(false);
        }
      } else if (response?.type === 'error') {
        setError(response.error?.message || 'Authentication failed');
        setIsLoading(false);
      } else if (response?.type === 'dismiss') {
        setIsLoading(false);
      }
    }
    handleResponse();
  }, [response, request, scheduleTokenRefresh]);

  const login = useCallback(async () => {
    setError(null);
    try {
      await promptAsync();
    } catch (err) {
      setError(err.message);
      Alert.alert('Login Error', err.message);
    }
  }, [promptAsync]);

  const logout = useCallback(async () => {
    setIsLoading(true);
    try {
      const tokens = await TokenManager.getTokens();
      if (tokens?.accessToken) {
        await TokenManager.revokeToken(tokens.accessToken);
      }
      if (tokens?.refreshToken) {
        await TokenManager.revokeToken(tokens.refreshToken);
      }
      await TokenManager.clearTokens();

      if (refreshTimerRef.current) {
        clearTimeout(refreshTimerRef.current);
      }

      setIsAuthenticated(false);
      setUserInfo(null);
      setError(null);
    } catch (err) {
      console.error('Logout error:', err);
      await TokenManager.clearTokens();
      setIsAuthenticated(false);
      setUserInfo(null);
    } finally {
      setIsLoading(false);
    }
  }, []);

  const refreshUserInfo = useCallback(async () => {
    try {
      const info = await ApiClient.getUserInfo();
      setUserInfo(info);
      return info;
    } catch (err) {
      if (err.message.includes('expired') || err.message.includes('Not authenticated')) {
        setIsAuthenticated(false);
        setUserInfo(null);
      }
      throw err;
    }
  }, []);

  return {
    isAuthenticated,
    isLoading,
    userInfo,
    error,
    login,
    logout,
    refreshUserInfo,
    request,
  };
}

