function LoginScreen({ onLogin, isLoading, error }) {
  return (
    <View style={styles.centerContainer}>
      <View style={styles.loginCard}>
        <Text style={styles.appTitle}>My App</Text>
        <Text style={styles.appSubtitle}>Sign in to continue</Text>

        {error && (
          <View style={styles.errorContainer}>
            <Text style={styles.errorText}>{error}</Text>
          </View>
        )}

        <TouchableOpacity
          style={[styles.loginButton, isLoading && styles.disabledButton]}
          onPress={onLogin}
          disabled={isLoading}
        >
          {isLoading ? (
            <ActivityIndicator color="#fff" />
          ) : (
            <Text style={styles.loginButtonText}>Sign In with OAuth</Text>
          )}
        </TouchableOpacity>

        <Text style={styles.securityNote}>
          You will be redirected to a secure login page
        </Text>
      </View>
    </View>
  );
}

